const { randomUUID } = require('node:crypto');

function createProject(name) {
  if (!name) throw new BadRequestError('Name is required');
  const projectId = randomUUID();
  projectsMap.set(projectId, { name });
  return { projectId };
}

module.exports = { createProject };
