      "path": "src/modules/tasks/service.js",
      "content": "const tasksMap = require('../../lib/sharedState').tasks; // Assuming shared state management
const { randomUUID } = require('node:crypto');

function createTask(projectId, status) {
  if (!status) throw new BadRequestError('Status is required');
  const taskId = randomUUID();
  tasksMap.set(taskId, { projectId, status });
  return { taskId };
}

function getTasksByStatus(projectId, status) {
  if (status === 'done') {
    return Array.from(tasksMap.values()).filter(task => task.projectId === projectId && task.status === 'done');
  }
  throw new BadRequestError('Invalid status filter');
}

module.exports = { createTask, getTasksByStatus };
